const products = $input.first().json || [];

if (products.length === 0) {
  return {
    products: [{name: "Imperium Classic Tee", category: "shirts", description: "Premium cotton t-shirt", price: 29.99}],
    peopleType: "solo",
    isSingle: true,
    isCuteCouple: false
  };
}

const isSingle = Math.random() < 0.7;
const peopleType = Math.random() < 0.5 ? 'solo' : (Math.random() < 0.625 ? 'couple' : 'group');

const byCategory = {};
products.forEach(p => {
  const cat = p.category || 'shirts';
  if (!byCategory[cat]) byCategory[cat] = [];
  byCategory[cat].push(p);
});

let selectedProducts = [];

if (isSingle) {
  const cats = Object.keys(byCategory);
  if (cats.length === 0) {
    selectedProducts = [products[0]];
  } else {
    const randCat = cats[Math.floor(Math.random() * cats.length)];
    const prods = byCategory[randCat];
    selectedProducts = [prods[Math.floor(Math.random() * prods.length)]];
  }
} else {
  const cats = Object.keys(byCategory);
  if (cats.length === 0) {
    selectedProducts = [products[0]];
  } else {
    const randCat = cats[Math.floor(Math.random() * cats.length)];
    const prods = byCategory[randCat];
    const numItems = Math.random() < 0.5 ? 2 : 3;
    const shuffled = prods.sort(() => 0.5 - Math.random());
    selectedProducts = shuffled.slice(0, Math.min(numItems, prods.length));
  }
}

if (peopleType !== 'group') {
  const categories = selectedProducts.map(p => p.category);
  if (categories.includes('hats') && categories.includes('beanies')) {
    const filtered = selectedProducts.filter(p => p.category !== 'hats');
    if (filtered.length > 0) selectedProducts = filtered;
  }
}

const isCuteCouple = peopleType === 'couple' && !isSingle;

return {
  products: selectedProducts,
  peopleType,
  isSingle,
  isCuteCouple
};
